			assertThat(QueryEvaluationUtility.isRepeatable(function)).isFalse();
			assertThat(QueryEvaluationUtility.isSafeForPlanConstantFolding(function)).isFalse();

			FunctionCall call = new FunctionCall(function.getURI());
			Filter filter = new Filter(new SingletonSet(), new Or(call, call.clone()));
			QueryRoot query = new QueryRoot(filter);

			optimize(mode, query);

			assertThat(filter.getCondition()).isInstanceOf(Or.class);
